  // Privacy tab
  "account.privacy.title": { es: "Analítica interna", en: "Internal analytics", it: "Analitica interna", de: "Interne Analyse", fr: "Analyse interne" },
  "account.privacy.desc": { es: "Usamos analítica propia y agregada (sin terceros) para entender cómo se usa la plataforma y mejorar el producto. Puedes desactivarla aquí. Si lo haces, dejaremos de registrar eventos de tu navegador inmediatamente.", en: "We use our own aggregated analytics (no third parties) to understand how the platform is used and improve the product. You can disable it here — if you do, we stop recording events from your browser immediately.", it: "Usiamo analitica interna aggregata (senza terze parti) per capire come viene usata la piattaforma e migliorarla. Puoi disattivarla qui. Se lo fai, smetteremo immediatamente di registrare eventi dal tuo browser.", de: "Wir verwenden eigene aggregierte Analyse (keine Dritten), um zu verstehen, wie die Plattform genutzt wird, und sie zu verbessern. Du kannst sie hier deaktivieren — dann zeichnen wir Ereignisse aus deinem Browser sofort nicht mehr auf.", fr: "Nous utilisons notre propre analyse agrégée (sans tiers) pour comprendre comment la plateforme est utilisée et l'améliorer. Vous pouvez la désactiver ici — dans ce cas, nous arrêtons immédiatement d'enregistrer les événements de votre navigateur." },
  "account.privacy.allow": { es: "Permitir analítica interna agregada", en: "Allow aggregated internal analytics", it: "Consenti analitica interna aggregata", de: "Aggregierte interne Analyse erlauben", fr: "Autoriser l'analyse interne agrégée" },
  "account.privacy.allowSub.before": { es: "Activado por defecto. No se comparte con terceros. ", en: "Enabled by default. Not shared with third parties. ", it: "Attivato per impostazione predefinita. Non condiviso con terzi. ", de: "Standardmäßig aktiviert. Wird nicht an Dritte weitergegeben. ", fr: "Activé par défaut. Non partagé avec des tiers. " },
  "account.privacy.allowSub.link": { es: "Más información", en: "Learn more", it: "Maggiori informazioni", de: "Mehr erfahren", fr: "En savoir plus" },

